import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { getHistory } from '../services/resume';
import { 
  DocumentTextIcon, 
  ChartBarIcon, 
  ArrowPathIcon,
  ClockIcon,
  CheckCircleIcon,
  SparklesIcon
} from '@heroicons/react/24/outline';

const Dashboard = () => {
  const { user } = useAuth();
  const [history, setHistory] = useState([]);
  const [stats, setStats] = useState({
    total: 0,
    avgAts: 0,
    highestMatch: 0
  });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadHistory();
  }, []);

  const loadHistory = async () => {
    try {
      const data = await getHistory();
      setHistory(data);
      
      if (data.length > 0) {
        const avg = data.reduce((acc, curr) => acc + curr.atsScore, 0) / data.length;
        const highest = Math.max(...data.map(item => item.matchPercentage));
        setStats({
          total: data.length,
          avgAts: Math.round(avg),
          highestMatch: highest
        });
      }
    } catch (error) {
      console.error('Failed to load history:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <ArrowPathIcon className="h-8 w-8 text-indigo-600 animate-spin" />
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      {/* Welcome Header */}
      <div className="mb-8">
        <h1 className="text-2xl font-bold text-gray-900">Dashboard</h1>
        <p className="text-gray-600">Welcome back, {user?.name}!</p>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
        <div className="bg-white rounded-lg shadow p-6">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm text-gray-500">Total Analyses</p>
              <p className="text-3xl font-bold text-gray-900">{stats.total}</p>
            </div>
            <DocumentTextIcon className="h-8 w-8 text-indigo-500" />
          </div>
        </div>

        <div className="bg-white rounded-lg shadow p-6">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm text-gray-500">Avg. ATS Score</p>
              <p className="text-3xl font-bold text-gray-900">{stats.avgAts}%</p>
            </div>
            <ChartBarIcon className="h-8 w-8 text-green-500" />
          </div>
        </div>

        <div className="bg-white rounded-lg shadow p-6">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm text-gray-500">Highest Match</p>
              <p className="text-3xl font-bold text-gray-900">{stats.highestMatch}%</p>
            </div>
            <CheckCircleIcon className="h-8 w-8 text-purple-500" />
          </div>
        </div>
      </div>

      {/* Quick Action */}
      <div className="mb-8">
        <Link to="/analyze">
          <div className="bg-indigo-50 border border-indigo-200 rounded-lg p-6 text-center hover:bg-indigo-100 transition">
            <SparklesIcon className="h-8 w-8 text-indigo-600 mx-auto mb-2" />
            <h3 className="text-lg font-semibold text-gray-900">Ready to analyze your resume?</h3>
            <p className="text-gray-600">Get instant AI-powered feedback</p>
          </div>
        </Link>
      </div>

      {/* Recent History */}
      <div className="bg-white rounded-lg shadow">
        <div className="p-6 border-b border-gray-200">
          <h2 className="text-lg font-semibold text-gray-900">Recent Analyses</h2>
        </div>
        
        {history.length === 0 ? (
          <div className="p-12 text-center">
            <DocumentTextIcon className="h-12 w-12 text-gray-400 mx-auto mb-4" />
            <p className="text-gray-500">No analysis history found</p>
            <Link to="/analyze">
              <button className="mt-4 px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700">
                Start Your First Analysis
              </button>
            </Link>
          </div>
        ) : (
          <div className="divide-y divide-gray-200">
            {history.map((item) => (
              <Link key={item._id} to={`/result/${item._id}`}>
                <div className="p-4 hover:bg-gray-50 transition">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center space-x-3">
                      <DocumentTextIcon className="h-5 w-5 text-gray-400" />
                      <div>
                        <p className="font-medium text-gray-900">{item.fileName || 'Resume Analysis'}</p>
                        <div className="flex items-center text-sm text-gray-500">
                          <ClockIcon className="h-4 w-4 mr-1" />
                          {new Date(item.createdAt).toLocaleDateString()}
                        </div>
                      </div>
                    </div>
                    <div className="flex items-center space-x-4">
                      <div className="text-right">
                        <p className="text-sm text-gray-500">ATS Score</p>
                        <p className={`font-semibold ${
                          item.atsScore >= 70 ? 'text-green-600' : 
                          item.atsScore >= 50 ? 'text-yellow-600' : 'text-red-600'
                        }`}>
                          {item.atsScore}%
                        </p>
                      </div>
                      <div className="text-right">
                        <p className="text-sm text-gray-500">Match</p>
                        <p className="font-semibold text-indigo-600">{item.matchPercentage}%</p>
                      </div>
                    </div>
                  </div>
                </div>
              </Link>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default Dashboard;
